import React from "react";
import logo from "../images/scale.png";

const Home = () => {
  return (
    <div className="container-fluid">
      <header className="d-flex flex-row align-items-center gap-2 bg-light">
        <img src={logo} alt="logo" style={{ width: "20px" }} className="ms-2" />
        <h5 className="my-1 p-1 fw-bold text-success">ניהול משרד עורך דין</h5>
      </header>
    </div>
  );
};

export default Home;
